#include <stdio.h>
#include <signal.h>
#include <string.h>
#include <unistd.h>

typedef struct {
    int signo;
    int code;
    pid_t sender_pid;
} SigRecord;

volatile int rec_count = 0;
SigRecord records[4];

void info_handler(int sig, siginfo_t *info, void *ctx) {
    (void)ctx;
    if (rec_count < 4) {
        records[rec_count].signo = sig;
        records[rec_count].code = info->si_code;
        records[rec_count].sender_pid = info->si_pid;
        rec_count++;
    }
}

const char *code_name(int code) {
    switch (code) {
        case SI_USER:  return "SI_USER";
        case SI_QUEUE: return "SI_QUEUE";
        default:       return "OTHER";
    }
}

int main(void) {
    pid_t my_pid = getpid();
    printf("My PID: reported\n");

    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_sigaction = info_handler;
    sa.sa_flags = SA_SIGINFO;
    sigemptyset(&sa.sa_mask);
    sigaction(SIGUSR1, &sa, NULL);
    sigaction(SIGUSR2, &sa, NULL);
    printf("SA_SIGINFO handlers installed\n");

    /* raise() -> SI_USER (kill/raise) */
    raise(SIGUSR1);

    /* sigqueue() -> SI_QUEUE */
    union sigval val = {.sival_int = 42};
    sigqueue(my_pid, SIGUSR1, val);

    /* Deuxieme signal */
    raise(SIGUSR2);

    printf("Signals received: %d\n", rec_count);
    for (int i = 0; i < rec_count; i++) {
        printf("  sig=%d code=%s sender=self\n",
               records[i].signo, code_name(records[i].code));
    }
    return 0;
}

